select *
from batch.job_step_instance
where tenant_id = #{tenantId}
  and id = #{id}

select *
from batch.job_step_instance
where tenant_id = #{tenantId}
  and job_task_id = #{jobTaskId}

select *
from batch.job_step_instance
where tenant_id = #{tenantId}
  and job_instance_id = #{jobInstanceId}
order by id asc

mapper.update:
update batch.job_step_instance
set step_status = 'RUNNING',
    started_at = coalesce(started_at, #{startedAt}),
    version = version + 1,
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and id = #{id}
  and version = #{expectedVersion}
  and step_status in ('CREATED', 'WAITING', 'READY', 'RETRYING')
